%% QEA2: Rover Mission - Map Selection & Leaderboard Setup
clc; clear; close all;

filename = 'leaderboard_data.mat';

if isfile(filename)
    load(filename);
else
    % Initialize empty arrays if the file doesn't exist yet
    saved_seeds = [];
    saved_complexities = [];
    saved_amplitudes = [];
end

fprintf('=== Welcome to the Rover Fuel Optimization Challenge ===\n'); %[output:4bcf3977]
mode = input('Choose Mode: [1] New Terrain | [2] Play Seed from Leaderboard: ');

if mode == 1 %[output:group:8c63a645]
    % 1. Generate New Terrain
    complexity = input('Enter Complexity (0.1 - 1.5): ');
    amplitude = input('Enter Amplitude (5 - 20): ');
    seed = randi(10000); % Generate a random integer seed
    fprintf('\nNew Map Generated! Seed: %d | Comp: %.1f | Amp: %.1f\n', seed, complexity, amplitude); %[output:15d8c1ca]
    saved_seeds = [saved_seeds; seed];
    saved_complexities = [saved_complexities; complexity];
    saved_amplitudes = [saved_amplitudes; amplitude];
    save(filename, 'saved_seeds', 'saved_complexities', 'saved_amplitudes');
    

else
    % 2. Replicate Previous Terrain
    if isempty(saved_seeds)
        disp('No previous terrains found! Generate a new one first.');
    else
        fprintf('\n--- Available Terrains ---\n');
        % Create a table for easy viewing
        T = table(saved_seeds, saved_complexities, saved_amplitudes, ...
            'VariableNames', {'Seed', 'Complexity', 'Amplitude'});
        disp(T);
        
        choice = input('Enter the Seed you want to play: ');
        % Logic to extract the specific complexity/amplitude based on the seed
        idx = find(saved_seeds == choice, 1);
        seed = saved_seeds(idx);
        complexity = saved_complexities(idx);
        amplitude = saved_amplitudes(idx);
    end
end %[output:group:8c63a645]

% --- Mathematical Core ---
rng(seed); % Lock the randomness to the seed
[x, y] = meshgrid(-10:0.2:10, -10:0.2:10);

% Randomized phases based on seed
p1 = rand * 2*pi; p2 = rand * 2*pi;
z = amplitude * (sin(complexity*x + p1) .* cos(complexity*y + p2));

% Calculate Gradients for Fuel Logic
[px, py] = gradient(z, 0.2, 0.2);

% --- Visualization ---
figure('Color', 'w'); %[output:1e555c99]
surf(x, y, z, 'EdgeColor', 'none'); %[output:1e555c99]
colormap summer; colorbar; %[output:1e555c99]
lighting gouraud; camlight; %[output:1e555c99]
title(['Level: ', num2str(seed), ' | Comp: ', num2str(complexity), ' | Amp: ', num2str(amplitude)]); %[output:1e555c99]
xlabel('X (m)'); ylabel('Y (m)'); zlabel('Elevation (m)'); %[output:1e555c99]
axis equal; %[output:1e555c99]

